+    fn assert_no_raw_params(events: &[CapturedEvent], raw_values: &[&str]) {
+        for event in events {
+            for (key, val) in &event.fields {
+                if key == "params_hash" || key == "message" {
+                    continue;
+                }
+                for raw in raw_values {
+                    assert!(
+                        !val.contains(raw),
+                        "raw param value {raw:?} leaked into log field {key}={val}"
+                    );
+                }
+            }
+        }
+    }
